unsigned long long run_event_based_simulation_optimization_4(Inputs in, SimulationData GSD, int mype)
{
	const char * optimization_name = "Optimization 4 - All Material Lookup Kernels + Material Sort";

	if( mype == 0)	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	if( mype == 0)	printf("Allocating additional device data required by kernel...\n");
	size_t total_sz = 0;

	GSD.p_energy_samples = (double *) malloc(in.lookups * sizeof(double));
	total_sz += in.lookups * sizeof(double);
	GSD.length_p_energy_samples = in.lookups;

	GSD.mat_samples = (int *) malloc(in.lookups * sizeof(int));
	total_sz += in.lookups * sizeof(int);
	GSD.length_mat_samples = in.lookups;

	if( mype == 0)	printf("Allocated an additional %.0lf MB of data on CPU.\n", total_sz/1024.0/1024.0);

	if( mype == 0)	printf("Beginning optimized simulation...\n");

	int nthreads = in.nthreads;

	#pragma omp parallel num_threads(nthreads)
	{
		#pragma omp for
		for( int i = 0; i < in.lookups; i++ )
		{
			uint64_t seed = STARTING_SEED;	
			seed = fast_forward_LCG(seed, 2*i);
			double p_energy = LCG_random_double(&seed);
			int mat         = pick_mat(&seed); 
			GSD.p_energy_samples[i] = p_energy;
			GSD.mat_samples[i] = mat;
		}
	}

	int n_lookups_per_material[12] = {0};
	for( int i = 0; i < in.lookups; i++ )
		n_lookups_per_material[GSD.mat_samples[i]]++;

	double * sorted_p_energy = (double *) malloc(in.lookups * sizeof(double));
	int * sorted_mat = (int *) malloc(in.lookups * sizeof(int));
	int offset = 0;
	for( int m = 0; m < 12; m++ )
	{
		for( int i = 0; i < in.lookups; i++ )
		{
			if( GSD.mat_samples[i] == m )
			{
				sorted_p_energy[offset] = GSD.p_energy_samples[i];
				sorted_mat[offset] = GSD.mat_samples[i];
				offset++;
			}
		}
	}
	free(GSD.p_energy_samples);
	free(GSD.mat_samples);
	GSD.p_energy_samples = sorted_p_energy;
	GSD.mat_samples = sorted_mat;

	offset = 0;
	for( int m = 0; m < 12; m++ )
	{
		int count = n_lookups_per_material[m];
		#pragma omp parallel num_threads(nthreads)
		{
			#pragma omp for
			for( int i = 0; i < count; i++ )
			{
				int idx = i + offset;
				int mat = GSD.mat_samples[idx];
				if( mat != m ) continue;

				double macro_xs_vector[5] = {0};

				calculate_macro_xs(
						GSD.p_energy_samples[idx],        
						mat,             
						in.n_isotopes,   
						in.n_gridpoints, 
						GSD.num_nucs,     
						GSD.concs,        
						GSD.unionized_energy_array, 
						GSD.index_grid,   
						GSD.nuclide_grid, 
						GSD.mats,         
						macro_xs_vector, 
						in.grid_type,    
						in.hash_bins,    
						GSD.max_num_nucs  
						);

				double max = -1.0;
				int max_idx = 0;
				for(int j = 0; j < 5; j++ )
				{
					if( macro_xs_vector[j] > max )
					{
						max = macro_xs_vector[j];
						max_idx = j;
					}
				}
				GSD.verification[idx] = max_idx+1;
			}
		}
		offset += count;
	}

	if( mype == 0)	printf("Reducing verification results...\n");

	unsigned long long verification_scalar = 0;
	for(int i=0; i<in.lookups; i++) verification_scalar += GSD.verification[i];

	free(GSD.p_energy_samples);
	free(GSD.mat_samples);

	return verification_scalar;
}

